changeSet.sql:
CREATE TABLE policies
(
	id serial,
	organization_id integer DEFAULT NULL,
	name character varying DEFAULT NULL,
	version double precision DEFAULT 0,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	created_by_id integer NOT NULL,
	approved_at timestamp without time zone DEFAULT NULL,
	approved_by_id integer NOT NULL,
	annual_review_date timestamp without time zone DEFAULT NULL,
	CONSTRAINT pk_policies PRIMARY KEY (id)
	, CONSTRAINT fk_policies_to_users_created FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_policies_to_users_approved FOREIGN KEY (approved_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_policies_organization ON policies (organization_id);
CREATE INDEX i_policies_organization_and_name ON policies (organization_id, name);
CREATE INDEX i_policies_name ON policies (name);
CREATE INDEX i_policies_created_by_id ON policies (created_by_id);
CREATE INDEX i_policies_approved_by_id ON policies (approved_by_id);
